21	const basePremiumByType: Record<string, number> = {
22	  amulet: 60,
23	  sword: 100,
24	  staff: 80,
25	  potion: 40,
26	  rune: 25,
27	  moonstone: 25,
28	};
29	
30	const PROCESSING_FEE = 5;
31	const BLOCK_OF_THREE_PREMIUM = 60;
32	const LOYALTY_DISCOUNT_RATE = 0.2;
33	const FIRST_INSURANCE_RATE = 0.1;
34	const FOLLOW_UP_DISCOUNT_RATE = 0.15;
35	
36	function surchargeRateFor(item: Item): number {
37	  let rate = 0;
38	  if (item.cursed) rate += 0.5;
39	  if ((item.enchantment ?? 0) >= 5) rate += 0.3;
40	  return rate;
41	}
42	
43	function surchargeFor(item: Item): number {
44	  return basePremiumByType[item.type] * surchargeRateFor(item);
45	}
46	
47	function premiumForTypeBlock(type: string, count: number): number {
48	  if (count === 3) return BLOCK_OF_THREE_PREMIUM;
49	  return count * basePremiumByType[type];
50	}
51	
52	export function quote(
53	  customer: Customer,
54	  items: Item[],
55	  options: QuoteOptions = {},
56	): QuoteResult {
57	  const countByType = items.reduce<Record<string, number>>((counts, item) => {
58	    counts[item.type] = (counts[item.type] ?? 0) + 1;
59	    return counts;
60	  }, {});
61	  const baseWithoutSurcharges = Object.entries(countByType).reduce(
62	    (sum, [type, count]) => sum + premiumForTypeBlock(type, count),
63	    0,
64	  );
65	  const surcharges = items.reduce((sum, item) => sum + surchargeFor(item), 0);
66	  const basePremium = baseWithoutSurcharges + surcharges;
67	
68	  const policyBase = baseWithoutSurcharges;
69	  let premium = basePremium;
70	  if (customer.yearsWithMHPCO >= 2) premium -= policyBase * LOYALTY_DISCOUNT_RATE;
71	  if (items.length > 0) premium += policyBase * FIRST_INSURANCE_RATE;
72	  if (options.followUp) premium -= policyBase * FOLLOW_UP_DISCOUNT_RATE;
73	  premium = Math.ceil(premium + PROCESSING_FEE);
74	
75	  return { basePremium, premium };
76	}
77	
78	export function claim(): unknown {
79	  return undefined;
80	}
